cd ..
$env:DOCKER_HOST = $env:DOCKER_HOST -ne $null ? $env:DOCKER_HOST : '192.168.2.166'
$env:DOCKER_REGISTRY = $env:DOCKER_REGISTRY -ne $null ? $env:DOCKER_REGISTRY : 'registry.cn-beijing.aliyuncs.com/amur'
docker buildx create --use
$dirs = Get-ChildItem -Path . -Filter Dockerfile -Recurse | Select-Object -ExpandProperty FullName

foreach ($dir in $dirs) {
  $pwd = Get-Location
  if ($dir -eq "tmp" -or $dir -eq "target") {
    continue
  }
  cd (Split-Path $dir)
  $dir_name = Split-Path (Get-Location) -Leaf
  if ($args[0] -eq "all") {
    Write-Host "Building: $dir_name"
    docker buildx build -t "$env:DOCKER_REGISTRY/$dir_name:latest" --push --platform linux/amd64,linux/arm64 .
    cd $pwd
    continue
  }
  if ($args -contains $dir_name -or $dir_name.StartsWith("home-") -and $args -contains ($dir_name -replace "home-", "")) {
    Write-Host "Building: $dir_name"
    docker buildx build -t "$env:DOCKER_REGISTRY/$dir_name:latest" --push --platform linux/amd64,linux/arm64 .
    cd $pwd
  }
  cd $pwd
}
